export class Font {
  readonly cssFontString: string;
  readonly baselineAdjustment: number;

  private constructor(readonly sizeInPixels: number, toCssFontString: (sizeInPixels: number) => string) {
    this.cssFontString = toCssFontString(sizeInPixels);
    this.baselineAdjustment = Math.round(sizeInPixels / 3);
  }

  static readonly button = new Font(18, (sizeInPixels) => `500 ${sizeInPixels}px Inter`);
  static readonly selector = new Font(16, (sizeInPixels) => `500 ${sizeInPixels}px Inter`);
  static readonly pad = new Font(14, (sizeInPixels) => `${sizeInPixels}px Inter`);
}
