import { SAMPLE_RATE } from './constants';
import { canvas } from './canvas';

let initSynths: () => void;

export function toInitSynths(fn: () => void) {
  initSynths = fn;
}

export const context = new AudioContext({
  latencyHint: 'balanced',
  sampleRate: SAMPLE_RATE,
});

const deviceId = await selectDevice(false);
const micStream = await navigator.mediaDevices.getUserMedia({
  audio: { deviceId, autoGainControl: false, echoCancellation: false },
});
export const mic = context.createMediaStreamSource(micStream);

// @ts-ignore -- not a real error, see https://v3.vitejs.dev/guide/assets.html
import workletUrl from './msynth-worklet.ts?worker&url';
await context.audioWorklet.addModule(workletUrl);

let webAudioState: 'need initialization' | 'initializing' | 'ready' = 'need initialization';

// When the iPad is turned off then turned back on, the audio context gets suspended.
// We need to resume it, and that only works when done in response to a user interaction.
canvas.addEventListener('pointerdown', async () => {
  if (context.state === 'suspended' || context.state === 'interrupted') {
    console.log('resuming context');
    await context.resume();
  }

  if (webAudioState === 'need initialization') {
    webAudioState = 'initializing';
    console.log('initializing');
    initSynths();
    webAudioState = 'ready';
    console.log('ready');
  }
});

async function selectDevice(useDefault = true, container?: HTMLElement) {
  const devices = await navigator.mediaDevices.enumerateDevices();

  if (useDefault) {
    const defaultDevice = devices.find((d) => d.label.toLowerCase().includes('default'));
    if (defaultDevice) {
      return defaultDevice.deviceId;
    }
  }

  return new Promise<string>((resolve) => {
    const containerEl = container || (document.getElementById('ui') as HTMLDivElement);
    const wrapper = tag('div');
    wrapper.style.position = 'absolute';
    wrapper.style.right = '0px';
    wrapper.style.top = '20px';
    wrapper.style.height = '100%';
    wrapper.style.width = '300px';
    wrapper.style.display = 'flex';
    wrapper.style.gap = '4px';
    wrapper.style.flexDirection = 'column';
    containerEl.appendChild(wrapper);

    wrapper.appendChild(tag('div', document.createTextNode('Select input device:')));

    for (const d of devices) {
      if (d.kind !== 'audioinput') {
        continue;
      }

      const button = document.createElement('button');
      button.textContent = d.label;
      button.onclick = (e) => {
        wrapper.remove();
        resolve(d.deviceId);
      };
      wrapper.appendChild(tag('div', button));
    }
  });

  function tag(name: string, ...children: any) {
    const el = document.createElement(name);
    for (const child of children) {
      el.appendChild(child);
    }
    return el;
  }
}
